function genericQueuePage(type){const headers={kyc:['Case','Customer','Review type','Reason','Age'],rwa:['Reference','Customer','Product / event','Value','Status'],remittance:['Reference','Customer','Route','Send amount','Status'],ucard:['Reference','Customer','Type','Value','Status'],reconciliation:['Reference','Source','Record type','Difference','Status'],support:['Case','Customer','Topic','Priority','Status']}[type];return `${pageHead()}<div class="toolbar"><div class="filters"><button class="filter active">${t('all')}</button><button class="filter">${t('review')}</button><button class="filter">${t('completed')}</button></div><button class="btn primary" data-action="new-case">＋ ${t('newCase')}</button></div><div class="table-wrap"><table><thead><tr>${headers.map(h=>`<th>${h}</th>`).join('')}<th>ACTION</th></tr></thead><tbody>${queueRows[type].map((r,i)=>`<tr data-record="${type}-${i}">${r.slice(0,5).map((c,j)=>`<td class="${j===0?'mono':''}">${j===4?status(c,r[5]):c}</td>`).join('')}<td><button class="btn small" data-action="open-record" data-type="${type}" data-index="${i}">${type==='rwa'?t('retry'):type==='reconciliation'?t('investigate'):t('viewUser')}</button></td></tr>`).join('')}</tbody></table></div>${type==='rwa'?partnerHealth():''}`}

function money(value,currency='USD'){return new Intl.NumberFormat(state.lang==='zh'?'zh-CN':'en-AU',{style:'currency',currency,minimumFractionDigits:2}).format(value)}
function assetAmount(value,currency){return `${Number(value).toLocaleString(state.lang==='zh'?'zh-CN':'en-AU',{minimumFractionDigits:2,maximumFractionDigits:2})} ${currency}`}
function rwaOperationsPage(){
  const f=state.rwaFilters;
  const filtered=rwaTransactions.filter(o=>(!f.query||`${o.id} ${o.user} ${o.userId} ${o.product} ${o.symbol}`.toLowerCase().includes(f.query.toLowerCase()))&&(!f.status||o.status===f.status)&&(!f.type||o.type===f.type));
  const completed=rwaTransactions.filter(o=>o.status==='Completed');
  const completedVolume=completed.reduce((s,o)=>s+(o.currency==='AUD'?o.amount/1.52:o.amount),0);
  const margin=rwaTransactions.filter(o=>o.status==='Completed').reduce((s,o)=>s+o.margin,0);
  const exceptions=rwaTransactions.filter(o=>o.status==='Failed').length;
  return `${pageHead()}<section class="metric-grid rwa-metrics">${metric(t('totalOrders'),rwaTransactions.length,'Current demo register','⌁')}${metric(t('completedVolume'),money(completedVolume),'Completed transactions only','✓','#17b58a','#eaf9f4')}${metric(t('feeRevenue'),money(margin),'Recognized at 0.20%','◆','#7857d8','#f1edff')}${metric(t('exceptionOrders'),exceptions,'Manual action available','!','#e45c64','#fff0f1')}</section><div class="notice" style="margin:13px 0"><b>i</b><span>${t('rwaFeeRule')}</span></div>
  <section class="filter-panel" style="margin-top:14px"><div class="filter-title"><div><strong>⌕ ${t('allTransactions')}</strong><small>${filtered.length} / ${rwaTransactions.length}</small></div><button class="text-link" data-action="reset-rwa-filters">${t('resetFilters')}</button></div><div class="rwa-filter-grid"><label><span>${t('transactionSearch')}</span><input id="rwaQuery" value="${f.query}" placeholder="ORD-71142 / Olivia / USTB" /></label><label><span>${t('transactionStatus')}</span><select id="rwaStatus"><option value="">${t('all')}</option>${['Completed','Processing','Failed','Retrying','Closed'].map(x=>`<option ${f.status===x?'selected':''}>${x}</option>`).join('')}</select></label><label><span>${t('transactionType')}</span><select id="rwaType"><option value="">${t('all')}</option>${['Buy','Sell','Income','Redemption'].map(x=>`<option ${f.type===x?'selected':''}>${x}</option>`).join('')}</select></label><button class="btn primary" data-action="apply-rwa-filters">${t('applyFilters')}</button></div></section>
  <div class="table-wrap"><table class="rwa-table"><thead><tr><th>${t('orderId')}</th><th>${t('user')}</th><th>${t('product')}</th><th>${t('type')}</th><th>${t('tradeAmount')}</th><th>${t('userFee')}</th><th>${t('partnerCost')}</th><th>${t('feeMargin')}</th><th>${t('revenueStatus')}</th><th>${t('transactionStatus')}</th><th>${t('createdAt')}</th><th>${t('actions')}</th></tr></thead><tbody>${filtered.length?filtered.map(o=>`<tr data-rwa-id="${o.id}"><td class="mono">${o.id}</td><td><strong class="cell-main">${o.user}</strong><small class="cell-sub">${o.userId}</small></td><td><strong class="cell-main">${o.symbol}</strong><small class="cell-sub">${o.product}</small></td><td>${o.type}</td><td>${money(o.amount,o.currency)}</td><td>${money(o.userFee,o.currency)}<small class="fee-rate">0.40%</small></td><td class="cost-cell">${money(o.partnerCost,o.currency)}<small class="fee-rate">0.20%</small></td><td class="margin-cell">+${money(o.margin,o.currency)}<small class="fee-rate">0.20%</small></td><td>${status(o.feeStatus,o.feeStatus==='Recognized'?'good':o.feeStatus==='Pending'?'warn':'neutral')}</td><td>${status(o.status,o.statusClass)}</td><td>${o.created}</td><td><button class="btn small" data-action="view-rwa-order" data-order="${o.id}">${t('viewDetails')}</button></td></tr>`).join(''):`<tr><td colspan="12"><div class="table-empty">${t('noTransactions')}</div></td></tr>`}</tbody></table></div>${partnerHealth()}`;
}

function fxOperationsPage(){
  const f=state.fxFilters;
  const filtered=fxConversions.filter(x=>(!f.query||`${x.id} ${x.orderId} ${x.user} ${x.provider}`.toLowerCase().includes(f.query.toLowerCase()))&&(!f.status||x.status===f.status)&&(!f.pair||x.pair===f.pair));
  const completed=fxConversions.filter(x=>x.status==='Completed');
  const sourceVolume=completed.filter(x=>x.sourceCcy==='AUDD').reduce((s,x)=>s+x.source,0);
  const toAud=(value,ccy)=>ccy==='AUDD'?value:value/0.65;
  const net=completed.reduce((s,x)=>s+toAud(x.netIncome,x.targetCcy),0);
  const gross=completed.reduce((s,x)=>s+toAud(x.grossIncome,x.targetCcy),0);
  const weighted=completed.reduce((s,x)=>s+x.netMarginBps,0)/(completed.length||1);
  const exceptions=fxConversions.filter(x=>['Expired','Reconciliation','Failed'].includes(x.status)).length;
  return `${pageHead()}<section class="metric-grid">${metric(t('fxVolume'),`A$ ${sourceVolume.toLocaleString(undefined,{maximumFractionDigits:0})}`,`${completed.length} completed conversions`,'⇌')}${metric(t('grossFxIncome'),money(gross,'AUD'),'Recognized • 20 bps gross','↗','#7857d8','#f1edff')}${metric(t('netFxIncome'),money(net,'AUD'),'Recognized reporting equivalent','◆','#17b58a','#eaf9f4')}${metric(t('fxExceptions'),exceptions,`${weighted.toFixed(1)} bps ${t('weightedNetMargin')}`,'!','#e45c64','#fff0f1')}</section>
  <section class="filter-panel" style="margin-top:14px"><div class="filter-title"><div><strong>⇌ ${t('conversionRecords')}</strong><small>${filtered.length} / ${fxConversions.length}</small></div><button class="text-link" data-action="reset-fx-filters">${t('resetFilters')}</button></div><div class="rwa-filter-grid"><label><span>${t('transactionSearch')}</span><input id="fxQuery" value="${f.query}" placeholder="FX-880148 / ORD-71148 / Olivia" /></label><label><span>${t('currencyPair')}</span><select id="fxPair"><option value="">${t('all')}</option>${[...new Set(fxConversions.map(x=>x.pair))].map(x=>`<option ${f.pair===x?'selected':''}>${x}</option>`).join('')}</select></label><label><span>${t('transactionStatus')}</span><select id="fxStatus"><option value="">${t('all')}</option>${[...new Set(fxConversions.map(x=>x.status))].map(x=>`<option ${f.status===x?'selected':''}>${x}</option>`).join('')}</select></label><button class="btn primary" data-action="apply-fx-filters">${t('applyFilters')}</button></div></section>
  <div class="table-wrap"><table class="fx-table"><thead><tr><th>${t('conversionId')}</th><th>${t('linkedOrder')}</th><th>${t('currencyPair')}</th><th>${t('sourceAmount')}</th><th>${t('customerRate')}</th><th>${t('executedRate')}</th><th>${t('grossFxIncome')}</th><th>${t('mmFee')}</th><th>${t('networkCost')}</th><th>${t('netFxIncome')}</th><th>${t('executionLatency')}</th><th>${t('transactionStatus')}</th><th>${t('actions')}</th></tr></thead><tbody>${filtered.length?filtered.map(x=>`<tr><td class="mono">${x.id}</td><td><strong class="cell-main">${x.orderId}</strong><small class="cell-sub">${x.user}</small></td><td><strong class="cell-main">${x.pair}</strong><small class="cell-sub">${x.direction}</small></td><td>${assetAmount(x.source,x.sourceCcy)}</td><td class="rate-cell">${x.customerRate.toFixed(6)}</td><td class="rate-cell">${x.executedRate===null?'—':x.executedRate.toFixed(6)}</td><td class="margin-cell">+${assetAmount(x.grossIncome,x.targetCcy)}</td><td class="cost-cell">${assetAmount(x.mmFee,x.targetCcy)}</td><td class="cost-cell">${assetAmount(x.networkCost,x.targetCcy)}</td><td class="margin-cell">+${assetAmount(x.netIncome,x.targetCcy)}</td><td>${x.executionMs?`${x.executionMs} ms`:'—'}</td><td>${status(x.status,x.statusClass)}</td><td><button class="btn small" data-action="view-fx" data-fx="${x.id}">${t('viewDetails')}</button></td></tr>`).join(''):`<tr><td colspan="13"><div class="table-empty">${t('noTransactions')}</div></td></tr>`}</tbody></table></div><div class="notice" style="margin-top:13px"><b>i</b><span>${t('pricingNote')}</span></div>${partnerHealth()}`;
}

function remittanceOperationsPage(){
  const f=state.remitFilters;
  const filtered=remittanceTransactions.filter(x=>(!f.query||`${x.id} ${x.user} ${x.userId} ${x.beneficiary} ${x.bank}`.toLowerCase().includes(f.query.toLowerCase()))&&(!f.status||x.status===f.status)&&(!f.country||x.country===f.country));
  const recognized=remittanceTransactions.filter(x=>x.feeStatus==='Recognized');
  const volume=recognized.reduce((s,x)=>s+x.source,0);
  const fees=recognized.reduce((s,x)=>s+x.userFee,0);
  const costs=recognized.reduce((s,x)=>s+x.providerCost,0);
  const income=recognized.reduce((s,x)=>s+x.margin,0);
  return `${pageHead()}<section class="metric-grid">${metric(t('remittanceVolume'),money(volume,'AUD'),`${recognized.length} completed payouts`,'↗')}${metric(t('remittanceFees'),assetAmount(fees,'AUDD'),t('feeFormula'),'＋','#7857d8','#f1edff')}${metric(t('remittanceCost'),assetAmount(costs,'AUDD'),t('costFormula'),'−','#f5a524','#fff5df')}${metric(t('remittanceIncome'),assetAmount(income,'AUDD'),t('marginFormula'),'◆','#17b58a','#eaf9f4')}</section><div class="notice" style="margin:13px 0"><b>i</b><span>${t('remittanceRule')}</span></div>
  <section class="filter-panel"><div class="filter-title"><div><strong>↗ ${t('remittanceRecords')}</strong><small>${filtered.length} / ${remittanceTransactions.length}</small></div><button class="text-link" data-action="reset-remit-filters">${t('resetFilters')}</button></div><div class="rwa-filter-grid"><label><span>${t('remitSearch')}</span><input id="remitQuery" value="${f.query}" placeholder="REM-30142 / Olivia / ANZ" /></label><label><span>${t('payoutCountry')}</span><select id="remitCountry"><option value="">${t('all')}</option>${[...new Set(remittanceTransactions.map(x=>x.country))].map(x=>`<option ${f.country===x?'selected':''}>${x}</option>`).join('')}</select></label><label><span>${t('transactionStatus')}</span><select id="remitStatus"><option value="">${t('all')}</option>${[...new Set(remittanceTransactions.map(x=>x.status))].map(x=>`<option ${f.status===x?'selected':''}>${x}</option>`).join('')}</select></label><button class="btn primary" data-action="apply-remit-filters">${t('applyFilters')}</button></div></section>
  <div class="table-wrap"><table class="remit-table"><thead><tr><th>${t('orderId')}</th><th>${t('user')}</th><th>${t('sendAmount')}</th><th>${t('payoutAmount')}</th><th>${t('beneficiaryBank')}</th><th>${t('bankAccount')}</th><th>${t('nameMatch')}</th><th>${t('userRemittanceFee')}</th><th>${t('providerRemittanceCost')}</th><th>${t('remittanceMargin')}</th><th>${t('revenueStatus')}</th><th>${t('transactionStatus')}</th><th>${t('actions')}</th></tr></thead><tbody>${filtered.length?filtered.map(x=>`<tr><td class="mono">${x.id}</td><td><strong class="cell-main">${x.user}</strong><small class="cell-sub">${x.userId}</small></td><td>${assetAmount(x.source,'AUDD')}</td><td>${x.payout?assetAmount(x.payout,x.payoutCcy):'—'}</td><td><strong class="cell-main">${x.bank}</strong><small class="cell-sub">${x.country}</small></td><td class="mono">${x.account}</td><td>${status(x.nameMatch,x.nameMatch==='Verified'?'good':'warn')}</td><td>${assetAmount(x.userFee,'AUDD')}<small class="fee-rate">${t('feeFormula')}</small></td><td class="cost-cell">${assetAmount(x.providerCost,'AUDD')}<small class="fee-rate">${t('costFormula')}</small></td><td class="margin-cell">+${assetAmount(x.margin,'AUDD')}<small class="fee-rate">${t('marginFormula')}</small></td><td>${status(x.feeStatus,x.feeStatus==='Recognized'?'good':x.feeStatus==='Pending'?'warn':'neutral')}</td><td>${status(x.status,x.statusClass)}</td><td><button class="btn small" data-action="view-remittance" data-remit="${x.id}">${t('viewDetails')}</button></td></tr>`).join(''):`<tr><td colspan="13"><div class="table-empty">${t('noTransactions')}</div></td></tr>`}</tbody></table></div>`;
}

function ucardOperationsPage(){
  const completedFunding=cardFundings.filter(x=>x.feeStatus==='Recognized');
  const fundingVolume=completedFunding.reduce((s,x)=>s+x.amount,0);
  const fundingIncome=completedFunding.reduce((s,x)=>s+x.margin,0);
  const settledSpend=cardTransactions.filter(x=>x.status==='Settled').reduce((s,x)=>s+x.billing,0);
  const content={products:cardProductsView,activations:cardActivationsView,funding:cardFundingView,transactions:cardTransactionsView}[state.ucardView]();
  return `${pageHead()}<section class="metric-grid">${metric(t('activeCards'),'1,862','Across all card types','▣')}${metric(t('fundingVolume'),assetAmount(fundingVolume,'AUDD'),`${completedFunding.length} completed funding records`,'↗','#1769e0','#edf5ff')}${metric(t('fundingIncome'),assetAmount(fundingIncome,'AUDD'),'Recognized funding margin','◆','#17b58a','#eaf9f4')}${metric(t('spendVolume'),money(settledSpend,'AUD'),'Settled transactions only','◎','#7857d8','#f1edff')}</section><div class="notice" style="margin:13px 0"><b>!</b><span>${t('cardFundingRule')}</span></div><div class="section-tabs card-tabs"><button class="${state.ucardView==='products'?'active':''}" data-ucard-view="products">${t('cardProducts')} <b>3</b></button><button class="${state.ucardView==='activations'?'active':''}" data-ucard-view="activations">${t('activationRecords')} <b>${cardActivations.length}</b></button><button class="${state.ucardView==='funding'?'active':''}" data-ucard-view="funding">${t('fundingRecords')} <b>${cardFundings.length}</b></button><button class="${state.ucardView==='transactions'?'active':''}" data-ucard-view="transactions">${t('cardTransactions')} <b>${cardTransactions.length}</b></button></div>${content}`;
}
function cardProductsView(){return `<div class="card-product-grid">${cardProducts.map(p=>`<article class="card-product ${p.colour}"><div class="mini-card"><span>AUDC</span><b>${p.type}</b><small>•••• 8888</small></div><h3>${p.type}</h3><p>${p.features}</p><div class="card-pricing"><div><span>${t('cardPrice')}</span><strong>${p.price}</strong></div><div><span>${t('fundingRate')}</span><strong>${p.feeRate.toFixed(2)}%</strong></div><div><span>${t('issuerCost')}</span><strong>${p.costRate.toFixed(2)}%</strong></div><div><span>${t('fundingMargin')}</span><strong class="margin-cell">${p.marginRate.toFixed(2)}%</strong></div></div></article>`).join('')}</div>`}
function cardActivationsView(){return `<div class="table-wrap"><table><thead><tr><th>${t('activationId')}</th><th>${L('Unified user','统一用户')}</th><th>${L('Issuer cardholder','发卡行持卡人')}</th><th>${t('cardId')}</th><th>${t('cardType')}</th><th>${t('maskedPan')}</th><th>${t('transactionStatus')}</th><th>${t('createdAt')}</th><th>${t('actions')}</th></tr></thead><tbody>${cardActivations.map(x=>{const u=canonicalUser(x.user);return `<tr><td class="mono">${x.id}</td><td>${unifiedUserCell(x.user)}</td><td class="mono">${u.cardholderId}</td><td class="mono">${x.cardId}</td><td>${x.type}</td><td class="mono">${x.pan}</td><td>${status(x.status,x.statusClass)}</td><td>${x.created}</td><td><button class="btn small" data-action="view-card-record" data-kind="activation" data-id="${x.id}">${t('viewDetails')}</button></td></tr>`}).join('')}</tbody></table></div>`}
function cardFundingView(){return `<div class="table-wrap"><table class="card-funding-table"><thead><tr><th>${t('fundingId')}</th><th>${L('Unified user / cardholder','统一用户 / 持卡人')}</th><th>${t('cardType')}</th><th>${t('maskedPan')}</th><th>${t('auddDebited')}</th><th>${t('fundingRate')}</th><th>${t('userFee')}</th><th>${t('issuerCost')}</th><th>${t('fundingMargin')}</th><th>${t('audCardCredit')}</th><th>${t('transactionStatus')}</th><th>${t('actions')}</th></tr></thead><tbody>${cardFundings.map(x=>`<tr><td class="mono">${x.id}</td><td>${unifiedUserCell(x.user)}</td><td>${x.type}</td><td class="mono">${x.pan}</td><td>${assetAmount(x.amount,'AUDD')}</td><td>${x.feeRate.toFixed(2)}%</td><td>${assetAmount(x.userFee,'AUDD')}</td><td class="cost-cell">${assetAmount(x.providerCost,'AUDD')}<small class="fee-rate">0.20%</small></td><td class="margin-cell">+${assetAmount(x.margin,'AUDD')}<small class="fee-rate">${(x.feeRate-x.costRate).toFixed(2)}%</small></td><td>${x.cardCredit?money(x.cardCredit,'AUD'):'—'}</td><td>${status(x.status,x.statusClass)}</td><td><button class="btn small" data-action="view-card-record" data-kind="funding" data-id="${x.id}">${t('viewDetails')}</button></td></tr>`).join('')}</tbody></table></div>`}
function cardTransactionsView(){return `<div class="table-wrap"><table class="card-spend-table"><thead><tr><th>Transaction ID</th><th>${L('Unified user / cardholder','统一用户 / 持卡人')}</th><th>${t('maskedPan')}</th><th>${t('cardType')}</th><th>${t('merchant')}</th><th>${t('originalAmount')}</th><th>${t('billingAmount')}</th><th>${t('issuerReference')}</th><th>${t('transactionStatus')}</th><th>${t('transactionDate')}</th><th>${t('actions')}</th></tr></thead><tbody>${cardTransactions.map(x=>`<tr><td class="mono">${x.id}</td><td>${unifiedUserCell(x.user)}</td><td class="mono">${x.card}</td><td>${x.type}</td><td><strong class="cell-main">${x.merchant}</strong><small class="cell-sub">${x.category}</small></td><td>${assetAmount(x.original,x.currency)}</td><td>${money(x.billing,'AUD')}</td><td class="mono">${x.issuerRef}</td><td>${status(x.status,x.statusClass)}</td><td>${x.created}</td><td><button class="btn small" data-action="view-card-record" data-kind="transaction" data-id="${x.id}">${t('viewDetails')}</button></td></tr>`).join('')}</tbody></table></div>`}

function auddPage(){return `${pageHead()}<section class="metric-grid">${metric('User AUDD liabilities','A$ 2.41M','1,284 account balances','◈')}${metric('Platform working inventory','A$ 3.16M','Available A$ 2.72M','▤','#7857d8','#f1edff')}${metric('Custody AUDD assets','A$ 5.77M','Reconciled 09:00 UTC','◇','#17b58a','#eaf9f4')}${metric('Held / pending','A$ 82.4K','17 risk or settlement holds','⏱','#f5a524','#fff6e5')}</section><section class="split-grid" style="margin-top:14px"><div class="panel"><div class="panel-head"><div><h2>${t('inventoryPosition')}</h2><p>Balances must not be netted across ownership classes</p></div></div><div class="panel-body"><div class="balance-stack"><div class="balance-row"><span>User available balances</span><strong>A$ 2,327,600</strong><small>Liability to platform customers</small></div><div class="balance-row"><span>User frozen balances</span><strong>A$ 82,400</strong><small>Orders, transfers and risk holds</small></div><div class="balance-row"><span>Platform-owned inventory</span><strong>A$ 3,160,000</strong><small>Purchased from AUDC for operations</small></div><div class="balance-row"><span>Partner settlement balances</span><strong>A$ 204,800</strong><small>Restricted for settlement only</small></div></div></div></div><div class="panel"><div class="panel-head"><div><h2>${t('ledger')}</h2><p>Double-entry evidence • immutable event references</p></div></div><div class="panel-body"><div class="timeline"><div class="timeline-item"><strong>External wallet transfer held • TRF-99218</strong><small>A$ 18,400 • KYT review • 10:42 UTC</small></div><div class="timeline-item"><strong>RWA income credited • INC-30812</strong><small>A$ 1,284.62 AUDD • 10:31 UTC</small></div><div class="timeline-item"><strong>Card funding completed • FND-55218</strong><small>A$ 1,500 AUDD → AUD card balance • final • 10:18 UTC</small></div><div class="timeline-item"><strong>Fiat gateway acquisition • FIAT-44012</strong><small>A$ 8,000 AUDD delivered • 09:56 UTC</small></div></div><div class="notice"><b>!</b><span>Card funding is a final conversion into the issuer’s AUD balance. It is not an AUDD withdrawal and cannot be reversed to AUDD.</span></div></div></div></section>`}
function partnerHealth(){return `<section class="panel" style="margin-top:14px"><div class="panel-head"><div><h2>${t('partners')}</h2><p>Provider status is illustrative and partner-dependent</p></div></div><div class="panel-body"><div class="partner-grid"><div class="partner"><div class="partner-top"><span class="partner-icon">RWA</span><span class="health"><i></i>Operational</span></div><strong>RWA Partner A</strong><small>API 99.96% • webhook p95 4.2s</small></div><div class="partner"><div class="partner-top"><span class="partner-icon">LP</span><span class="health warn"><i></i>Degraded</span></div><strong>Liquidity Partner</strong><small>Quote rejection 2.8% • elevated</small></div><div class="partner"><div class="partner-top"><span class="partner-icon">CST</span><span class="health"><i></i>Operational</span></div><strong>Custody / MPC</strong><small>Last reconciliation 09:00 UTC</small></div></div></div></section>`}
function systemPage(){return `${pageHead()}${partnerHealth()}<section class="split-grid" style="margin-top:14px"><div class="panel"><div class="panel-head"><div><h2>Roles & approvals</h2><p>Least privilege and maker-checker controls</p></div></div><div class="panel-body"><div class="balance-stack"><div class="balance-row"><span>Operations</span><strong>12 users</strong><small>Orders, transfers and service cases</small></div><div class="balance-row"><span>Compliance & Risk</span><strong>6 users</strong><small>KYC, KYT, sanctions and manual review</small></div><div class="balance-row"><span>Finance & Treasury</span><strong>5 users</strong><small>Ledger, inventory and reconciliation</small></div></div></div></div><div class="panel"><div class="panel-head"><div><h2>Recent audit events</h2><p>Append-only operational history</p></div></div><div class="panel-body"><div class="timeline"><div class="timeline-item"><strong>Fee rule viewed by Product Admin</strong><small>CFG-1881 • 11:06 UTC</small></div><div class="timeline-item"><strong>KYC case approved by Risk Operator</strong><small>KYC-8829 • 10:58 UTC</small></div><div class="timeline-item"><strong>Reconciliation item assigned</strong><small>REC-19062 • 10:51 UTC</small></div></div></div></div></section>`}

function walletAccountsPanel(){return `<section class="panel" style="margin-top:14px"><div class="panel-head"><div><h2>${L('User wallet accounts','用户钱包账户')}</h2><p>${L('Wallets are linked to the canonical Platform UID; balances and wallet status remain independently controlled.','钱包关联统一 Platform UID；余额和钱包状态仍独立管理。')}</p></div></div><div class="table-wrap"><table><thead><tr><th>${L('Unified user','统一用户')}</th><th>${L('Wallet ID','钱包编号')}</th><th>${L('Custody address','托管地址')}</th><th>${L('Available AUDD','可用 AUDD')}</th><th>${L('Frozen AUDD','冻结 AUDD')}</th><th>KYC</th><th>${L('Wallet status','钱包状态')}</th><th>${t('actions')}</th></tr></thead><tbody>${users.map(u=>`<tr data-user="${u.id}"><td>${unifiedUserCell(u.name)}</td><td class="mono">${u.walletId}</td><td class="mono">${u.walletAddress}</td><td>A$ ${u.audd}</td><td>A$ ${u.frozen}</td><td>${status(u.kyc,u.kycClass)}</td><td>${status(u.walletStatus,stateTone(u.walletStatus))}</td><td><button class="btn small" data-user="${u.id}">${L('Open user 360','查看用户360')}</button></td></tr>`).join('')}</tbody></table></div></section>`}
function walletTransferOperationsPanel(){
  const rows=state.walletTransfers.map(transfer => ({
    ...transfer,
    networkFee: Number(transfer.networkFee).toFixed(2),
    platformFee: Number(transfer.platformFee).toFixed(2),
  }));
  const tone=value=>value==='confirmed'?'good':value==='refunded'?'neutral':value==='failed'?'bad':value==='risk_review'?'warn':'info';
  return `<section class="panel" style="margin-top:14px"><div class="panel-head"><div><h2>${L('External wallet transfer operations','外部钱包转账运营')}</h2><p>${L('Live local API records · KYT, reservation, provider outcome and fee evidence','本地 API 实时记录 · KYT、余额冻结、供应商结果和费用凭证')}</p></div><button class="btn" data-action="refresh-wallet-transfers">${L('Refresh','刷新')}</button></div><div class="table-wrap"><table><thead><tr><th>${L('Transfer','转账编号')}</th><th>Platform UID</th><th>${L('Destination','目标钱包')}</th><th>${L('Send amount','发送金额')}</th><th>${L('Fees','费用')}</th><th>KYT</th><th>${L('Status','状态')}</th><th>${t('actions')}</th></tr></thead><tbody>${rows.length?rows.map(x=>`<tr><td class="mono">${x.id.slice(0,8)}…<small class="cell-sub">${x.providerReference||'—'}</small></td><td class="mono">${x.platformUid}</td><td><strong class="cell-main">${x.destination.label}</strong><small class="cell-sub mono">${x.destination.address.slice(0,10)}…${x.destination.address.slice(-6)}</small></td><td>${assetAmount(Number(x.sendAmount),'AUDD')}</td><td>${assetAmount(Number(x.networkFee)+Number(x.platformFee),'AUDD')}<small class="cell-sub">Network ${x.networkFee} · Platform ${x.platformFee}</small></td><td>${status(x.riskResult,stateTone(x.riskResult))}</td><td>${status(x.status,tone(x.status))}</td><td>${['broadcasting','risk_review'].includes(x.status)?`<button class="btn small" data-action="wallet-transfer-confirm" data-transfer="${x.id}">${L('Confirm','确认成功')}</button> <button class="btn small danger" data-action="wallet-transfer-fail" data-transfer="${x.id}">${L('Fail & refund','失败并退款')}</button>`:'—'}</td></tr>`).join(''):`<tr><td colspan="8"><div class="table-empty">${L('No local API transfer records yet','暂无本地 API 转账记录')}</div></td></tr>`}</tbody></table></div></section>`;
}
function escapeHtml(value){return String(value??'').replace(/[&<>'"]/g,character=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[character]))}
function providerEventTone(value){return /confirmed|matched/i.test(value)?'good':/dead_letter|missing_ledger/i.test(value)?'bad':/retry_scheduled/i.test(value)?'warn':/received/i.test(value)?'info':'neutral'}
function providerEventTime(value){return value?new Date(value).toLocaleString(state.lang==='zh'?'zh-CN':'en-AU'):'—'}
function providerEventOperationsPanel(){
  const filters=state.providerEventFilters;
  const rows=state.providerEvents;
  return `<section class="panel provider-evidence-panel" style="margin-top:14px"><div class="panel-head"><div><h2>${L('Provider webhook evidence','供应商 Webhook 事件凭证')}</h2><p>${L('Read-only processing, retry, dead-letter and ledger reconciliation evidence','只读查看处理、重试、死信和账本对账凭证')}</p></div><button class="btn" data-action="refresh-provider-events">${L('Refresh','刷新')}</button></div><div class="panel-body provider-filter-body"><div class="provider-evidence-note"><b>${L('Read only','只读')}</b><span>${L('This view cannot replay, requeue or correct ledger records.','此视图不能重放、重新入队或更正账本记录。')}</span></div><div class="provider-filter-grid"><label><span>${L('Processing result','处理结果')}</span><select id="providerProcessingResult"><option value="">${L('All results','全部结果')}</option>${['received','confirmed','refunded','retry_scheduled','dead_letter','ignored_terminal'].map(value=>`<option value="${value}" ${filters.processingResult===value?'selected':''}>${value}</option>`).join('')}</select></label><label><span>${L('Reconciliation evidence','对账凭证')}</span><select id="providerEvidenceResult"><option value="">${L('All evidence','全部凭证')}</option>${['matched','missing_ledger','not_applicable'].map(value=>`<option value="${value}" ${filters.evidenceResult===value?'selected':''}>${value}</option>`).join('')}</select></label><div class="filter-submit"><button class="btn primary" data-action="apply-provider-event-filters">${t('applyFilters')}</button><button class="btn" data-action="reset-provider-event-filters">${t('resetFilters')}</button></div></div></div><div class="table-wrap"><table class="provider-event-table"><thead><tr><th>${L('Event identity','事件标识')}</th><th>${L('Event type','事件类型')}</th><th>${L('Processing result','处理结果')}</th><th>${L('Attempts','尝试次数')}</th><th>${L('Linked transfer','关联转账')}</th><th>${L('Retry / dead letter','重试 / 死信')}</th><th>${L('Reconciliation','对账')}</th><th>${t('actions')}</th></tr></thead><tbody>${rows.length?rows.map(event=>`<tr><td><strong class="cell-main mono">${escapeHtml(event.providerEventId)}</strong><small class="cell-sub">${escapeHtml(event.provider)} · ${escapeHtml(event.providerReference||'—')}</small></td><td class="mono">${escapeHtml(event.eventType)}</td><td>${status(escapeHtml(event.processingResult),providerEventTone(event.processingResult))}<small class="cell-sub">${event.lastErrorCode?escapeHtml(event.lastErrorCode):providerEventTime(event.processedAt)}</small></td><td><strong class="cell-main">${Number(event.attemptCount||0)} / ${Number(event.maxAttempts||0)}</strong></td><td>${event.transfer?`<strong class="cell-main mono">${escapeHtml(event.transfer.id.slice(0,8))}…</strong><small class="cell-sub">${escapeHtml(event.transfer.platformUid)} · ${escapeHtml(event.transfer.status)}</small>`:'—'}</td><td><strong class="cell-main">${event.deadLetteredAt?L('Dead lettered','已进入死信'):event.nextAttemptAt?L('Retry scheduled','已安排重试'):'—'}</strong><small class="cell-sub">${providerEventTime(event.deadLetteredAt||event.nextAttemptAt)}</small></td><td>${event.reconciliation?`${status(escapeHtml(event.reconciliation.result),providerEventTone(event.reconciliation.result))}<small class="cell-sub mono">${escapeHtml(event.reconciliation.ledgerReference||'—')}</small>`:'—'}</td><td><button class="btn small" data-action="view-provider-event" data-event="${escapeHtml(event.id)}">${L('View evidence','查看凭证')}</button></td></tr>`).join(''):`<tr><td colspan="8"><div class="table-empty">${L('No matching provider events','暂无匹配的供应商事件')}</div></td></tr>`}</tbody></table></div></section>`;
}
function auddAccountsPage(){return auddPage()+walletAccountsPanel()+walletTransferOperationsPanel()+providerEventOperationsPanel()}

function renderPage(){
  const renderers={overview:overviewDashboardPage,users:usersPage,kyc:()=>genericQueuePage('kyc'),audd:auddAccountsPage,rwa:rwaOperationsPage,fx:fxOperationsPage,remittance:remittanceOperationsPage,ucard:ucardOperationsPage,reconciliation:reconciliationPage,support:()=>genericQueuePage('support'),configuration:configurationPage,system:systemPartnersPage};
  document.getElementById('view').innerHTML=`<div class="page-enter">${renderers[state.page]()}</div>`;
  document.getElementById('breadcrumb').textContent=t(pageMeta[state.page][1]); renderNav(); applyI18n();
}
function applyI18n(){document.querySelectorAll('[data-i18n]').forEach(el=>el.textContent=t(el.dataset.i18n));document.querySelectorAll('[data-i18n-placeholder]').forEach(el=>el.placeholder=t(el.dataset.i18nPlaceholder));document.getElementById('languageLabel').textContent=state.lang==='en'?'EN':'中文';document.documentElement.lang=state.lang==='en'?'en':'zh-CN'}
function openUser(id){const u=users.find(x=>x.id===id)||users[0];openDrawer(`<div class="drawer-head"><h2>${t('viewUser')}</h2><button class="drawer-close" data-action="close-drawer">×</button></div><div class="drawer-body"><section class="profile-hero"><span class="avatar">${u.initials}</span><div><h3>${u.name}</h3><p>${u.email} • ${u.id}</p></div>${status(u.kyc,u.kycClass)}</section><section class="detail-section"><h3>${t('accountOverview')}</h3><div class="detail-grid"><div class="detail"><span>${t('available')} AUDD</span><strong>A$ ${u.audd}</strong></div><div class="detail"><span>${t('frozen')} AUDD</span><strong>A$ 1,240.00</strong></div><div class="detail"><span>RWA portfolio</span><strong>${u.rwa}</strong></div><div class="detail"><span>U-Card balance</span><strong>A$ 2,186.40</strong></div></div></section><section class="detail-section"><h3>${t('identity')}</h3><div class="detail-grid"><div class="detail"><span>${t('country')}</span><strong>${u.country}</strong></div><div class="detail"><span>${t('risk')}</span><strong>${u.risk}</strong></div><div class="detail"><span>KYC assurance</span><strong>Level 2</strong></div><div class="detail"><span>${t('partnerSubaccount')}</span><strong class="mono">RWA-A-88142</strong></div></div></section><section class="detail-section"><h3>${t('recentActivity')}</h3><div class="timeline"><div class="timeline-item"><strong>RWA order submitted</strong><small>US Treasury Token • US$ 10,000 • 10:42 UTC</small></div><div class="timeline-item"><strong>AUDD account funded</strong><small>A$ 12,000 • Fiat gateway • 09:56 UTC</small></div><div class="timeline-item"><strong>Login verified</strong><small>Sydney, AU • trusted device • 09:48 UTC</small></div></div></section><div class="drawer-actions"><button class="btn primary" data-action="approve">${t('approve')}</button><button class="btn" data-action="request-info">${t('requestInfo')}</button><button class="btn danger">Restrict account</button></div></div>`)}
function openRecord(type,index){const r=queueRows[type][index];openDrawer(`<div class="drawer-head"><h2>${r[0]}</h2><button class="drawer-close" data-action="close-drawer">×</button></div><div class="drawer-body"><div class="notice"><b>i</b><span>${t('demoOnly')}</span></div><section class="detail-section"><h3>Record details</h3><div class="detail-grid">${r.slice(0,5).map((v,i)=>`<div class="detail"><span>Field ${i+1}</span><strong>${v}</strong></div>`).join('')}</div></section><section class="detail-section"><h3>Processing evidence</h3><div class="timeline"><div class="timeline-item"><strong>Platform event created</strong><small>Idempotency reference captured</small></div><div class="timeline-item"><strong>Partner request submitted</strong><small>Callback pending or exception returned</small></div><div class="timeline-item"><strong>Manual queue assigned</strong><small>Operator action and audit trail required</small></div></div></section><div class="drawer-actions"><button class="btn primary" data-action="${type==='rwa'?'retry':'resolve'}">${type==='rwa'?t('retry'):t('resolve')}</button><button class="btn" data-action="request-info">${t('requestInfo')}</button></div></div>`)}
function openRwaOrder(id){const o=rwaTransactions.find(x=>x.id===id);if(!o)return;const exception=o.status==='Failed';const fx=fxConversions.find(x=>x.orderId===o.id);openDrawer(`<div class="drawer-head"><div><small class="mono">${o.id}</small><h2>${o.symbol} • ${o.type}</h2></div><button class="drawer-close" data-action="close-drawer">×</button></div><div class="drawer-body"><section class="order-hero"><div><span>${t('tradeAmount')}</span><strong>${money(o.amount,o.currency)}</strong><small>${o.product}</small></div>${status(o.status,o.statusClass)}</section><section class="detail-section"><h3>${t('transactionOverview')}</h3><div class="detail-grid"><div class="detail"><span>${t('user')}</span><strong>${o.user}</strong></div><div class="detail"><span>${t('type')}</span><strong>${o.type}</strong></div><div class="detail"><span>${t('partnerReference')}</span><strong class="mono">${o.partnerRef}</strong></div><div class="detail"><span>${t('settlementRoute')}</span><strong>${o.route}</strong></div></div></section><section class="detail-section"><h3>${t('feeBreakdown')}</h3><div class="fee-waterfall"><div><span>${t('userFee')} • 0.40%</span><strong>${money(o.userFee,o.currency)}</strong></div><i>−</i><div><span>${t('partnerCost')} • 0.20%</span><strong class="cost-cell">${money(o.partnerCost,o.currency)}</strong></div><i>=</i><div class="margin"><span>${t('feeMargin')} • 0.20%</span><strong>${money(o.margin,o.currency)}</strong></div></div><div style="margin-top:8px">${status(o.feeStatus,o.feeStatus==='Recognized'?'good':o.feeStatus==='Pending'?'warn':'neutral')}</div></section><section class="detail-section"><h3>${t('fx')}</h3>${fx?`<div class="linked-record"><div><span class="mono">${fx.id}</span><strong>${fx.pair} • ${status(fx.status,fx.statusClass)}</strong><small>${t('netFxIncome')}: +${assetAmount(fx.netIncome,fx.targetCcy)} • ${t('executionLatency')}: ${fx.executionMs||'—'} ms</small></div><button class="btn small" data-action="view-fx" data-fx="${fx.id}">${t('viewDetails')}</button></div>`:`<div class="notice"><b>i</b><span>${t('noConversion')}</span></div>`}</section><section class="detail-section"><h3>${t('orderTimeline')}</h3><div class="timeline"><div class="timeline-item"><strong>Order and final quote accepted</strong><small>${o.created} • user AUDD amount frozen</small></div><div class="timeline-item"><strong>Partner execution request</strong><small>${o.partnerRef} • ${o.note}</small></div><div class="timeline-item"><strong>${exception?'Exception assigned for manual action':'Latest order state recorded'}</strong><small>Immutable audit event retained</small></div></div></section>${exception?`<div class="notice"><b>!</b><span>${t('closeOrderWarning')}</span></div><div class="drawer-actions"><button class="btn primary" data-action="retry-rwa-order" data-order="${o.id}">${t('retryOrder')}</button><button class="btn danger" data-action="close-rwa-order" data-order="${o.id}">${t('closeOrder')}</button></div>`:`<div class="drawer-actions"><button class="btn" data-action="close-drawer">${t('close')}</button></div>`}</div>`)}
function openFxConversion(id){const x=fxConversions.find(v=>v.id===id);if(!x)return;openDrawer(`<div class="drawer-head"><div><small class="mono">${x.id}</small><h2>${x.pair} • ${t('conversionDetail')}</h2></div><button class="drawer-close" data-action="close-drawer">×</button></div><div class="drawer-body"><section class="order-hero"><div><span>${t('sourceAmount')}</span><strong>${assetAmount(x.source,x.sourceCcy)}</strong><small>${x.direction} • ${x.provider}</small></div>${status(x.status,x.statusClass)}</section><section class="detail-section"><h3>${t('pricingBreakdown')}</h3><div class="rate-grid"><div><span>${t('benchmarkRate')}</span><strong>${x.referenceRate.toFixed(6)}</strong></div><div><span>${t('customerRate')}</span><strong>${x.customerRate.toFixed(6)}</strong></div><div><span>${t('executedRate')}</span><strong>${x.executedRate===null?'—':x.executedRate.toFixed(6)}</strong></div><div><span>${t('customerSpread')}</span><strong>${x.customerSpreadBps} bps</strong></div><div><span>${t('mmExecutionSpread')}</span><strong>${x.mmSpreadBps} bps</strong></div><div><span>${t('rateDifference')}</span><strong>${x.spreadBps} bps</strong></div><div><span>${t('mmFeeRate')}</span><strong>${x.mmFeeBps} bps</strong></div><div><span>${t('netMarginRate')}</span><strong>${x.netMarginBps} bps</strong></div></div><div class="fx-profit"><div><span>${t('grossFxIncome')}</span><strong>+${assetAmount(x.grossIncome,x.targetCcy)}</strong></div><i>−</i><div><span>${t('mmFee')}</span><strong>${assetAmount(x.mmFee,x.targetCcy)}</strong></div><i>−</i><div><span>${t('networkCost')}</span><strong>${assetAmount(x.networkCost,x.targetCcy)}</strong></div><i>=</i><div class="net"><span>${t('netFxIncome')}</span><strong>+${assetAmount(x.netIncome,x.targetCcy)}</strong></div></div><div style="margin-top:8px">${status(x.profitStatus,x.profitStatus==='Recognized'?'good':x.profitStatus==='Pending'?'warn':'neutral')}</div></section><section class="detail-section"><h3>Execution evidence</h3><div class="detail-grid"><div class="detail"><span>${t('linkedOrder')}</span><strong class="mono">${x.orderId}</strong></div><div class="detail"><span>${t('provider')}</span><strong>${x.provider}</strong></div><div class="detail"><span>${t('quoteId')}</span><strong class="mono">${x.quoteId}</strong></div><div class="detail"><span>${t('fillId')}</span><strong class="mono">${x.fillId}</strong></div><div class="detail"><span>${t('quoteLatency')}</span><strong>${x.quoteMs} ms</strong></div><div class="detail"><span>${t('executionLatency')}</span><strong>${x.executionMs||'—'} ms</strong></div><div class="detail"><span>${t('mmAcquired')}</span><strong>${assetAmount(x.mmAcquired,x.targetCcy)}</strong></div><div class="detail"><span>${t('customerSettlement')}</span><strong>${assetAmount(x.target,x.targetCcy)}</strong></div></div></section><div class="notice"><b>i</b><span>${t('pricingNote')}</span></div><div class="drawer-actions"><button class="btn primary" data-action="view-linked-rwa" data-order="${x.orderId}">${t('viewRwaOrder')}</button><button class="btn" data-action="close-drawer">${t('close')}</button></div></div>`)}
function openRemittance(id){const x=remittanceTransactions.find(v=>v.id===id);if(!x)return;openDrawer(`<div class="drawer-head"><div><small class="mono">${x.id}</small><h2>${t('payoutDetail')}</h2></div><button class="drawer-close" data-action="close-drawer">×</button></div><div class="drawer-body"><section class="order-hero"><div><span>${t('sendAmount')}</span><strong>${assetAmount(x.source,'AUDD')}</strong><small>${x.country} • ${x.payoutCcy}</small></div>${status(x.status,x.statusClass)}</section><section class="detail-section"><h3>${t('feeBreakdown')}</h3><div class="remit-fee-grid"><div><span>${t('percentageFee')} • 1.00%</span><strong>${assetAmount(x.source*.01,'AUDD')}</strong></div><i>＋</i><div><span>${t('fixedFee')}</span><strong>5.00 AUDD</strong></div><i>=</i><div><span>${t('userRemittanceFee')}</span><strong>${assetAmount(x.userFee,'AUDD')}</strong></div><i>−</i><div><span>${t('providerRemittanceCost')} • 0.50%</span><strong class="cost-cell">${assetAmount(x.providerCost,'AUDD')}</strong></div><i>=</i><div class="net"><span>${t('remittanceMargin')}</span><strong>+${assetAmount(x.margin,'AUDD')}</strong></div></div><div style="margin-top:8px">${status(x.feeStatus,x.feeStatus==='Recognized'?'good':x.feeStatus==='Pending'?'warn':'neutral')}</div></section><section class="detail-section"><h3>${t('beneficiaryBankInfo')}</h3><div class="bank-card"><div class="bank-card-head"><div><strong>${x.bank}</strong><small>${x.country}</small></div>${status(t('sameNameVerified'),x.nameMatch==='Verified'?'good':'warn')}</div><div class="detail-grid"><div class="detail"><span>${t('beneficiary')}</span><strong>${x.beneficiary}</strong></div><div class="detail"><span>${t('bankAccount')}</span><strong class="mono">${x.account}</strong></div><div class="detail"><span>${t('swiftBic')}</span><strong class="mono">${x.swift}</strong></div><div class="detail"><span>${t('routingCode')}</span><strong class="mono">${x.routing}</strong></div><div class="detail detail-wide"><span>${t('bankAddress')}</span><strong>${x.address}</strong></div><div class="detail"><span>${t('payoutAmount')}</span><strong>${x.payout?assetAmount(x.payout,x.payoutCcy):'—'}</strong></div></div></div></section><section class="detail-section"><h3>${t('payoutTimeline')}</h3><div class="timeline"><div class="timeline-item"><strong>Quote accepted and AUDD frozen</strong><small>${x.created} • customer and fee amounts recorded</small></div><div class="timeline-item"><strong>Same-name account check</strong><small>${x.nameMatch} • beneficiary ${x.beneficiary}</small></div><div class="timeline-item"><strong>Provider payout instruction</strong><small>${x.providerRef} • ${x.provider}</small></div><div class="timeline-item"><strong>Latest payout state</strong><small>${x.status} • completed ${x.completed}</small></div></div></section><div class="notice"><b>i</b><span>Demo banking data is fictional and masked. Production access must be role-controlled and audited.</span></div><div class="drawer-actions"><button class="btn" data-action="close-drawer">${t('close')}</button></div></div>`)}
function openCardRecord(kind,id){
  if(kind==='funding'){const x=cardFundings.find(v=>v.id===id);if(!x)return;openDrawer(`<div class="drawer-head"><div><small class="mono">${x.id}</small><h2>${t('fundingDetail')}</h2></div><button class="drawer-close" data-action="close-drawer">×</button></div><div class="drawer-body"><section class="order-hero"><div><span>${t('auddDebited')}</span><strong>${assetAmount(x.amount,'AUDD')}</strong><small>${x.type} • ${x.pan}</small></div>${status(x.status,x.statusClass)}</section><section class="detail-section"><h3>${t('feeBreakdown')}</h3><div class="fee-waterfall"><div><span>${t('userFee')} • ${x.feeRate.toFixed(2)}%</span><strong>${assetAmount(x.userFee,'AUDD')}</strong></div><i>−</i><div><span>${t('issuerCost')} • 0.20%</span><strong class="cost-cell">${assetAmount(x.providerCost,'AUDD')}</strong></div><i>=</i><div class="margin"><span>${t('fundingMargin')} • ${(x.feeRate-x.costRate).toFixed(2)}%</span><strong>${assetAmount(x.margin,'AUDD')}</strong></div></div></section><section class="detail-section"><h3>${t('transactionOverview')}</h3><div class="detail-grid"><div class="detail"><span>${t('user')}</span><strong>${x.user}</strong></div><div class="detail"><span>${t('cardId')}</span><strong class="mono">${x.cardId}</strong></div><div class="detail"><span>${t('issuerReference')}</span><strong class="mono">${x.issuerRef}</strong></div><div class="detail"><span>${t('audCardCredit')}</span><strong>${x.cardCredit?money(x.cardCredit,'AUD'):'—'}</strong></div></div></section><div class="notice"><b>!</b><span>${t('cardFundingRule')}</span></div><div class="drawer-actions"><button class="btn" data-action="close-drawer">${t('close')}</button></div></div>`);return}
  if(kind==='activation'){const x=cardActivations.find(v=>v.id===id);if(!x)return;openDrawer(`<div class="drawer-head"><div><small class="mono">${x.id}</small><h2>${t('activationDetail')}</h2></div><button class="drawer-close" data-action="close-drawer">×</button></div><div class="drawer-body"><section class="order-hero"><div><span>${t('cardType')}</span><strong>${x.type}</strong><small>${x.pan}</small></div>${status(x.status,x.statusClass)}</section><section class="detail-section"><div class="detail-grid"><div class="detail"><span>${t('user')}</span><strong>${x.user}</strong></div><div class="detail"><span>${t('cardId')}</span><strong class="mono">${x.cardId}</strong></div><div class="detail"><span>${t('country')}</span><strong>${x.country}</strong></div><div class="detail"><span>${t('issuerReference')}</span><strong class="mono">${x.issuerRef}</strong></div></div></section><div class="drawer-actions"><button class="btn" data-action="close-drawer">${t('close')}</button></div></div>`);return}
  const x=cardTransactions.find(v=>v.id===id);if(!x)return;openDrawer(`<div class="drawer-head"><div><small class="mono">${x.id}</small><h2>${t('transactionDetail')}</h2></div><button class="drawer-close" data-action="close-drawer">×</button></div><div class="drawer-body"><section class="order-hero"><div><span>${t('billingAmount')}</span><strong>${money(x.billing,'AUD')}</strong><small>${x.merchant} • ${x.category}</small></div>${status(x.status,x.statusClass)}</section><section class="detail-section"><div class="detail-grid"><div class="detail"><span>${t('user')}</span><strong>${x.user}</strong></div><div class="detail"><span>${t('maskedPan')}</span><strong class="mono">${x.card}</strong></div><div class="detail"><span>${t('originalAmount')}</span><strong>${assetAmount(x.original,x.currency)}</strong></div><div class="detail"><span>${t('issuerReference')}</span><strong class="mono">${x.issuerRef}</strong></div><div class="detail"><span>${t('transactionDate')}</span><strong>${x.created}</strong></div><div class="detail"><span>${t('cardType')}</span><strong>${x.type}</strong></div></div></section><div class="notice"><b>i</b><span>Refunds, reversals and disputes follow issuer rules and return to the AUD card balance where applicable.</span></div><div class="drawer-actions"><button class="btn" data-action="close-drawer">${t('close')}</button></div></div>`)
}
function openAddUser(){openDrawer(`<div class="drawer-head"><h2>${t('createUser')}</h2><button class="drawer-close" data-action="close-drawer">×</button></div><div class="drawer-body"><div class="notice"><b>i</b><span>${t('createUserHint')}</span></div><div class="form-stack"><label><span>${t('nameFilter')}</span><input value="Alex Taylor" /></label><label><span>Email</span><input value="alex.taylor@example.demo" /></label><label><span>${t('phone')}</span><input value="+61 400 000 000" /></label><label><span>${t('country')}</span><select><option>Australia</option><option>New Zealand</option><option>Singapore</option></select></label><label><span>${t('memberGroup')}</span><select>${userGroups.filter(g=>g.name!=='Restricted').map(g=>`<option>${g.name}</option>`).join('')}</select></label></div><div class="drawer-actions"><button class="btn primary" data-action="save-demo-record">${t('saveDraft')}</button><button class="btn" data-action="close-drawer">${t('close')}</button></div></div>`)}
function openAddGroup(){openDrawer(`<div class="drawer-head"><h2>${t('createGroup')}</h2><button class="drawer-close" data-action="close-drawer">×</button></div><div class="drawer-body"><div class="notice"><b>i</b><span>Group benefits, pricing and service eligibility require approved configuration and audit history.</span></div><div class="form-stack"><label><span>${t('groupName')}</span><input value="Silver" /></label><label><span>${t('benefits')}</span><textarea>Standard access with campaign pricing eligibility</textarea></label><label><span>Fee profile</span><select><option>Standard Fee Profile</option><option>Preferred Fee Profile</option></select></label><label><span>Default KYC requirement</span><select><option>Risk-based / service dependent</option><option>Level 2 required</option></select></label></div><div class="drawer-actions"><button class="btn primary" data-action="save-demo-record">${t('saveDraft')}</button><button class="btn" data-action="close-drawer">${t('close')}</button></div></div>`)}
function openDrawer(html){const layer=document.getElementById('drawerLayer');document.getElementById('drawer').innerHTML=html;layer.hidden=false}
function closeDrawer(){document.getElementById('drawerLayer').hidden=true}
let toastTimer;function toast(msg){const el=document.getElementById('toast');el.textContent=msg;el.classList.add('show');clearTimeout(toastTimer);toastTimer=setTimeout(()=>el.classList.remove('show'),2600)}

document.addEventListener('click',e=>{
  const page=e.target.closest('[data-page]')?.dataset.page;if(page){state.page=page;renderPage();return}
  const usersView=e.target.closest('[data-users-view]')?.dataset.usersView;if(usersView){state.usersView=usersView;renderPage();return}
  const ucardView=e.target.closest('[data-ucard-view]')?.dataset.ucardView;if(ucardView){state.ucardView=ucardView;renderPage();return}
  const reconView=e.target.closest('[data-recon-view]')?.dataset.reconView;if(reconView){state.reconView=reconView;renderPage();return}
  const overviewPeriod=e.target.closest('[data-overview-period]')?.dataset.overviewPeriod;if(overviewPeriod){state.overviewPeriod=overviewPeriod;renderPage();return}
  const configView=e.target.closest('[data-config-view]')?.dataset.configView;if(configView){state.configView=configView;renderPage();return}
  const systemView=e.target.closest('[data-system-view]')?.dataset.systemView;if(systemView){state.systemView=systemView;renderPage();return}
  const user=e.target.closest('[data-user]')?.dataset.user;if(user){openUser(user);return}
  const action=e.target.closest('[data-action]')?.dataset.action;if(!action)return;
  if(action==='language'){state.lang=state.lang==='en'?'zh':'en';localStorage.setItem('audc-admin-lang',state.lang);renderPage()}
  if(action==='close-drawer')closeDrawer();
  if(action==='open-record'){const b=e.target.closest('[data-action]');openRecord(b.dataset.type,Number(b.dataset.index))}
  if(action==='view-rwa-order'){openRwaOrder(e.target.closest('[data-action]').dataset.order)}
  if(action==='view-fx'){openFxConversion(e.target.closest('[data-action]').dataset.fx)}
  if(action==='view-remittance'){openRemittance(e.target.closest('[data-action]').dataset.remit)}
  if(action==='view-card-record'){const b=e.target.closest('[data-action]');openCardRecord(b.dataset.kind,b.dataset.id)}
  if(action==='view-recon'){openReconRecord(e.target.closest('[data-action]').dataset.recon)}
  if(action==='edit-config'){const b=e.target.closest('[data-action]');openConfigEditor(b.dataset.kind,b.dataset.config)}
  if(action==='view-config-version'){openConfigurationVersion(e.target.closest('[data-action]').dataset.config)}
  if(action==='new-config-rule'){openNewConfigRule()}
  if(action==='export-config')toast(t('demoOnly'))
  if(action==='view-partner'){openPartnerDetail(e.target.closest('[data-action]').dataset.partner)}
  if(action==='view-integration'){openIntegrationDetail(e.target.closest('[data-action]').dataset.integration)}
  if(action==='edit-service-matrix'){const code=e.target.closest('[data-action]').dataset.country;const x=serviceMatrix.find(v=>v.code===code);openGenericSystemRecord(x.country,L('Service activation requires approved legal, compliance and partner assessments.','服务开放需要完成法律、合规及合作方评估。'))}
  if(action==='view-role'){openGenericSystemRecord(e.target.closest('[data-action]').dataset.role,L('Role permissions follow least privilege and maker-checker separation.','角色权限遵循最小权限及双人复核隔离。'))}
  if(action==='view-audit'){openGenericSystemRecord(e.target.closest('[data-action]').dataset.audit,L('Audit events are append-only and retain actor, target, time and result.','审计事件只追加保存，并记录操作人、目标、时间及结果。'))}
  if(action==='view-linked-rwa'){openRwaOrder(e.target.closest('[data-action]').dataset.order)}
  if(action==='approve'){toast(t('approvedMsg'));closeDrawer()}
  if(action==='request-info'){toast(t('infoMsg'));closeDrawer()}
  if(action==='retry'){toast(t('retryMsg'));closeDrawer()}
  if(action==='resolve'){toast(t('resolvedMsg'));closeDrawer()}
  if(action==='new-case')toast(t('demoOnly'));
  if(action==='add-user')openAddUser();
  if(action==='add-group')openAddGroup();
  if(action==='save-demo-record'){toast(t('demoOnly'));closeDrawer()}
  if(action==='apply-user-filters'){
    state.userFilters={name:document.getElementById('filterName').value.trim(),phone:document.getElementById('filterPhone').value.trim(),country:document.getElementById('filterCountry').value,group:document.getElementById('filterGroup').value,kyc:document.getElementById('filterKyc').value};renderPage();
  }
  if(action==='reset-user-filters'){state.userFilters={name:'',phone:'',country:'',group:'',kyc:''};renderPage()}
  if(action==='apply-rwa-filters'){
    state.rwaFilters={query:document.getElementById('rwaQuery').value.trim(),status:document.getElementById('rwaStatus').value,type:document.getElementById('rwaType').value};renderPage();
  }
  if(action==='reset-rwa-filters'){state.rwaFilters={query:'',status:'',type:''};renderPage()}
  if(action==='apply-fx-filters'){
    state.fxFilters={query:document.getElementById('fxQuery').value.trim(),status:document.getElementById('fxStatus').value,pair:document.getElementById('fxPair').value};renderPage();
  }
  if(action==='reset-fx-filters'){state.fxFilters={query:'',status:'',pair:''};renderPage()}
  if(action==='apply-remit-filters'){
    state.remitFilters={query:document.getElementById('remitQuery').value.trim(),status:document.getElementById('remitStatus').value,country:document.getElementById('remitCountry').value};renderPage();
  }
  if(action==='reset-remit-filters'){state.remitFilters={query:'',status:'',country:''};renderPage()}
  if(action==='apply-recon-filters'){
    state.reconFilters={from:document.getElementById('reconFrom').value,to:document.getElementById('reconTo').value,cycle:document.getElementById('reconCycle').value,category:document.getElementById('reconCategory').value,status:document.getElementById('reconStatus').value};renderPage();
  }
  if(action==='reset-recon-filters'){state.reconFilters={from:'2026-06-01',to:'2026-06-19',cycle:'',category:'',status:''};renderPage()}
  if(action==='retry-rwa-order'){
    const o=rwaTransactions.find(x=>x.id===e.target.closest('[data-action]').dataset.order);if(o){o.status='Retrying';o.statusClass='info';o.note='Manual retry submitted with a new idempotency key.';}toast(t('retrySuccess'));closeDrawer();renderPage();
  }
  if(action==='close-rwa-order'){
    const o=rwaTransactions.find(x=>x.id===e.target.closest('[data-action]').dataset.order);if(o){o.status='Closed';o.statusClass='neutral';o.note='Closed by operator; frozen value queued for release.';}toast(t('closeSuccess'));closeDrawer();renderPage();
  }
  if(action==='refresh-wallet-transfers')syncLocalWalletTransfers(true);
  if(action==='wallet-transfer-confirm')setLocalWalletTransferOutcome(e.target.closest('[data-action]').dataset.transfer,'confirmed');
  if(action==='wallet-transfer-fail')setLocalWalletTransferOutcome(e.target.closest('[data-action]').dataset.transfer,'failed');
  if(action==='refresh-provider-events')syncLocalProviderEvents(true);
  if(action==='apply-provider-event-filters'){
    state.providerEventFilters={processingResult:document.getElementById('providerProcessingResult').value,evidenceResult:document.getElementById('providerEvidenceResult').value};syncLocalProviderEvents();
  }
  if(action==='reset-provider-event-filters'){state.providerEventFilters={processingResult:'',evidenceResult:''};syncLocalProviderEvents()}
  if(action==='view-provider-event')openProviderEventDetail(e.target.closest('[data-action]').dataset.event);
  if(action==='notifications'){state.page='support';renderPage()}
});
document.getElementById('globalSearch').addEventListener('keydown',e=>{if(e.key==='Enter'){e.preventDefault();const q=e.target.value.trim().toLowerCase();const cardOwner=cardActivations.find(c=>`${c.cardId} ${c.pan} ${c.issuerRef}`.toLowerCase().includes(q));const u=users.find(x=>`${x.name} ${x.email} ${x.phone} ${x.id} ${x.walletId} ${x.walletAddress} ${x.rwaAccount} ${x.cardholderId}`.toLowerCase().includes(q))||users.find(x=>x.id===cardOwner?.userId)||users[0];openUser(u.id);toast(t('searchResult'))}});
openUser=function(id){const u=canonicalUser(id),cards=cardActivations.filter(c=>c.userId===u.id);openDrawer(`<div class="drawer-head"><div><small>Platform UID · <span class="mono">${u.id}</span></small><h2>${L('Unified user 360','统一用户 360')}</h2></div><button class="drawer-close" data-action="close-drawer">×</button></div><div class="drawer-body"><section class="profile-hero"><span class="avatar">${u.initials}</span><div><h3>${u.name}</h3><p>${u.email} · ${u.phone}</p></div>${status(u.kyc,u.kycClass)}</section><section class="detail-section"><h3>${L('Linked accounts and service status','关联账户与业务状态')}</h3><div class="linked-account-grid"><article class="linked-account"><small>${L('Platform account','平台账户')}</small><strong class="mono">${u.id}</strong>${status(u.platformStatus,stateTone(u.platformStatus))}</article><article class="linked-account"><small>${L('AUDD wallet account','AUDD 钱包账户')}</small><strong class="mono">${u.walletId}</strong><span class="mono subline">${u.walletAddress}</span>${status(u.walletStatus,stateTone(u.walletStatus))}</article><article class="linked-account"><small>${L('RWA partner account','RWA 合作方账户')}</small><strong class="mono">${u.rwaAccount}</strong>${status(u.rwaStatus,stateTone(u.rwaStatus))}</article><article class="linked-account"><small>${L('Issuer cardholder account','发卡行持卡人账户')}</small><strong class="mono">${u.cardholderId}</strong><span class="subline">${cards.length} ${L('linked card(s)','张关联卡')}</span>${status(u.cardholderStatus,stateTone(u.cardholderStatus))}</article></div><div class="identity-note">${L('Platform UID is the canonical identity. Wallet, RWA and cardholder IDs are linked service accounts—not separate users.','Platform UID 是唯一主身份；钱包、RWA 和持卡人编号均为关联业务账户，并非独立用户。')}</div></section><section class="detail-section"><h3>${t('accountOverview')}</h3><div class="detail-grid"><div class="detail"><span>${t('available')} AUDD</span><strong>A$ ${u.audd}</strong></div><div class="detail"><span>${t('frozen')} AUDD</span><strong>A$ ${u.frozen}</strong></div><div class="detail"><span>RWA portfolio</span><strong>${u.rwa}</strong></div><div class="detail"><span>${L('Linked cards','关联卡片')}</span><strong>${cards.map(c=>c.pan).join(', ')||'—'}</strong></div></div></section><section class="detail-section"><h3>${t('identity')}</h3><div class="detail-grid"><div class="detail"><span>${t('country')}</span><strong>${u.country}</strong></div><div class="detail"><span>${t('memberGroup')}</span><strong>${u.group}</strong></div><div class="detail"><span>${t('risk')}</span><strong>${u.risk}</strong></div><div class="detail"><span>${t('kycStatus')}</span><strong>${u.kyc}</strong></div></div></section><div class="drawer-actions"><button class="btn primary" data-action="approve">${t('approve')}</button><button class="btn" data-action="request-info">${t('requestInfo')}</button><button class="btn danger">${L('Restrict platform account','限制平台账户')}</button></div></div>`)};

async function syncLocalPlatformUsers(){
  try{
    const response=await fetch('http://127.0.0.1:3001/api/v1/users',{headers:{'x-admin-key':'local_admin_change_me'}});if(!response.ok)return;
    const payload=await response.json();let changed=false;
    for(const x of payload.items||[]){
      const existing=users.find(u=>u.id===x.platformUid);
      const name=`${x.legalFirstName} ${x.legalLastName}`.trim();
      const synced={id:x.platformUid,initials:`${x.legalFirstName?.[0]||''}${x.legalLastName?.[0]||''}`.toUpperCase(),name,email:x.email,phone:x.mobile,country:x.countryOfResidence,group:'Standard',kyc:x.emailVerified&&x.mobileVerified?`Contacts verified · MFA ${x.mfaStatus}`:'Contact verification pending',kycClass:x.emailVerified&&x.mobileVerified?'good':'pending',audd:Number(x.auddBalance||0).toLocaleString('en-AU',{minimumFractionDigits:2,maximumFractionDigits:2}),frozen:Number(x.pendingTransferAmount||0).toLocaleString('en-AU',{minimumFractionDigits:2,maximumFractionDigits:2}),rwa:'—',risk:'Low',riskClass:'good',active:'Local API',walletId:x.walletAccountCode||'Not opened',walletAddress:x.walletAccountCode?'Managed custody · provider deferred':'Pending custody setup',rwaAccount:'Not opened',cardholderId:'Not opened',platformStatus:x.status==='active'?'Active':'Pending verification',walletStatus:x.walletAccountCode?'Active':'Not opened',rwaStatus:'Not opened',cardholderStatus:'Not opened'};
      if(existing)Object.assign(existing,synced);else users.unshift(synced);changed=true;
    }
    if(changed&&['users','overview','audd'].includes(state.page))renderPage();
  }catch{}
}

async function syncLocalWalletTransfers(showMessage=false){
  try{
    const response=await fetch('http://127.0.0.1:3001/api/v1/admin/wallet-transfers',{headers:{'x-admin-key':'local_admin_change_me'}});
    if(!response.ok)throw new Error('transfer_query_failed');
    const payload=await response.json();state.walletTransfers=payload.items||[];
    if(state.page==='audd')renderPage();
    if(showMessage)toast(L('Transfer records refreshed','转账记录已刷新'));
  }catch{if(showMessage)toast(L('Local transfer API unavailable','本地转账 API 不可用'))}
}

async function syncLocalProviderEvents(showMessage=false){
  try{
    const params=new URLSearchParams({limit:'100'});
    if(state.providerEventFilters.processingResult)params.set('processingResult',state.providerEventFilters.processingResult);
    if(state.providerEventFilters.evidenceResult)params.set('evidenceResult',state.providerEventFilters.evidenceResult);
    const response=await fetch(`http://127.0.0.1:3001/api/v1/admin/provider-webhook-events?${params}`,{headers:{'x-admin-key':'local_admin_change_me'}});
    if(!response.ok)throw new Error('provider_event_query_failed');
    const payload=await response.json();state.providerEvents=payload.items||[];
    if(state.page==='audd')renderPage();
    if(showMessage)toast(L('Provider event evidence refreshed','供应商事件凭证已刷新'));
  }catch{if(showMessage)toast(L('Provider event API unavailable','供应商事件 API 不可用'))}
}

async function openProviderEventDetail(eventId){
  try{
    const response=await fetch(`http://127.0.0.1:3001/api/v1/admin/provider-webhook-events/${encodeURIComponent(eventId)}`,{headers:{'x-admin-key':'local_admin_change_me'}});
    if(!response.ok)throw new Error('provider_event_detail_failed');
    const event=await response.json();
    const transfer=event.transfer;
    const reconciliation=event.reconciliation;
    const attempts=event.attempts||[];
    const auditEvents=event.auditEvents||[];
    openDrawer(`<div class="drawer-head"><div><small>${L('Provider event evidence','供应商事件凭证')}</small><h2 class="mono">${escapeHtml(event.providerEventId)}</h2></div><button class="drawer-close" data-action="close-drawer">×</button></div><div class="drawer-body"><div class="provider-detail-state"><div><span>${escapeHtml(event.provider)} · ${escapeHtml(event.eventType)}</span><strong>${escapeHtml(event.providerReference||'—')}</strong></div>${status(escapeHtml(event.processingResult),providerEventTone(event.processingResult))}</div><section class="detail-section"><h3>${L('Processing evidence','处理凭证')}</h3><div class="detail-grid"><div class="detail"><span>${L('Attempts','尝试次数')}</span><strong>${Number(event.attemptCount||0)} / ${Number(event.maxAttempts||0)}</strong></div><div class="detail"><span>${L('Last error','最后错误')}</span><strong>${escapeHtml(event.lastErrorCode||'—')}</strong></div><div class="detail"><span>${L('Received','接收时间')}</span><strong>${providerEventTime(event.receivedAt)}</strong></div><div class="detail"><span>${L('Processed','处理时间')}</span><strong>${providerEventTime(event.processedAt)}</strong></div><div class="detail"><span>${L('Next retry','下次重试')}</span><strong>${providerEventTime(event.nextAttemptAt)}</strong></div><div class="detail"><span>${L('Dead lettered','进入死信')}</span><strong>${providerEventTime(event.deadLetteredAt)}</strong></div></div></section><section class="detail-section"><h3>${L('Linked transfer','关联转账')}</h3>${transfer?`<div class="detail-grid"><div class="detail"><span>${L('Transfer / user','转账 / 用户')}</span><strong class="mono">${escapeHtml(transfer.id)}<br>${escapeHtml(transfer.platformUid)}</strong></div><div class="detail"><span>${L('Status','状态')}</span><strong>${escapeHtml(transfer.status)}</strong></div><div class="detail"><span>${L('Value','金额')}</span><strong>${assetAmount(Number(transfer.sendAmount),escapeHtml(transfer.asset))}</strong></div><div class="detail"><span>${L('Total debit','总扣款')}</span><strong>${assetAmount(Number(transfer.totalDebit),escapeHtml(transfer.asset))}</strong></div><div class="detail detail-wide"><span>${L('Transaction hash / failure','交易哈希 / 失败码')}</span><strong class="evidence-hash mono">${escapeHtml(transfer.transactionHash||transfer.failureCode||'—')}</strong></div></div>`:`<div class="provider-empty-detail">${L('No transfer linked to this event.','此事件未关联转账。')}</div>`}</section><section class="detail-section"><h3>${L('Reconciliation evidence','对账凭证')}</h3>${reconciliation?`<div class="detail-grid"><div class="detail"><span>${L('Result','结果')}</span><strong>${escapeHtml(reconciliation.result)}</strong></div><div class="detail"><span>${L('Recorded','记录时间')}</span><strong>${providerEventTime(reconciliation.recordedAt)}</strong></div><div class="detail detail-wide"><span>${L('Ledger reference / transaction','账本引用 / 交易')}</span><strong class="evidence-hash mono">${escapeHtml(reconciliation.ledgerReference||'—')}<br>${escapeHtml(reconciliation.ledgerTransactionId||'—')}</strong></div></div>`:`<div class="provider-empty-detail">${L('No reconciliation evidence recorded.','尚未记录对账凭证。')}</div>`}</section><section class="detail-section"><h3>${L('Payload identity','载荷身份')}</h3><div class="detail"><span>SHA-256</span><strong class="evidence-hash mono">${escapeHtml(event.payloadHash)}</strong></div><pre class="evidence-code">${escapeHtml(JSON.stringify(event.payload,null,2))}</pre></section><section class="detail-section"><h3>${L('Processing attempts','处理尝试')}</h3><div class="timeline">${attempts.length?attempts.map(attempt=>`<div class="timeline-item"><strong>#${Number(attempt.attemptNumber)} · ${escapeHtml(attempt.outcome)}</strong><small>${providerEventTime(attempt.attemptedAt)}${attempt.errorCode?` · ${escapeHtml(attempt.errorCode)}`:''}${attempt.nextAttemptAt?` · ${L('next','下次')} ${providerEventTime(attempt.nextAttemptAt)}`:''}</small></div>`).join(''):`<div class="provider-empty-detail">${L('No attempt evidence.','暂无尝试凭证。')}</div>`}</div></section><section class="detail-section"><h3>${L('Immutable audit timeline','不可变审计时间线')}</h3><div class="timeline">${auditEvents.length?auditEvents.map(audit=>`<div class="timeline-item"><strong>${escapeHtml(audit.action)}</strong><small>${providerEventTime(audit.occurredAt)} · ${escapeHtml(audit.actorType)}${audit.actorId?` / ${escapeHtml(audit.actorId)}`:''}</small><small class="audit-metadata mono">${escapeHtml(JSON.stringify(audit.metadata||{}))}</small></div>`).join(''):`<div class="provider-empty-detail">${L('No audit events.','暂无审计事件。')}</div>`}</div></section><div class="drawer-actions"><button class="btn" data-action="close-drawer">${t('close')}</button></div></div>`);
  }catch{toast(L('Provider event detail unavailable','供应商事件详情不可用'))}
}

async function setLocalWalletTransferOutcome(transferId,outcome){
  try{
    const response=await fetch(`http://127.0.0.1:3001/api/v1/wallet/transfers/${transferId}/mock-outcome`,{
      method:'POST',headers:{'x-admin-key':'local_admin_change_me','content-type':'application/json'},body:JSON.stringify({outcome})
    });
    const result=await response.json();if(!response.ok)throw new Error(result.message||'provider_update_failed');
    toast(outcome==='confirmed'?L('Mock chain confirmation completed','模拟链上确认完成'):L('Provider failure recorded and AUDD refunded','供应商失败已记录，AUDD 已退回'));
    await Promise.all([syncLocalWalletTransfers(),syncLocalPlatformUsers()]);
  }catch(error){toast(String(error.message||error))}
}

